import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.CQMe4Urg.js";const c=JSON.parse('{"title":"第八章 记忆系统 -- 让 Agent 记住你是谁","description":"","frontmatter":{},"headers":[],"relativePath":"08-memory/index.md","filePath":"08-memory/index.md","lastUpdated":1776333512000}'),o={name:"08-memory/index.md"};function n(i,t,l,h,s,m){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="第八章-记忆系统-让-agent-记住你是谁" tabindex="-1">第八章 记忆系统 -- 让 Agent 记住你是谁 <a class="header-anchor" href="#第八章-记忆系统-让-agent-记住你是谁" aria-label="Permalink to &quot;第八章 记忆系统 -- 让 Agent 记住你是谁&quot;">​</a></h1><p>你跟 ChatGPT 聊了一下午，关掉窗口再回来，它完全不记得你是谁。你跟 Agent 说&quot;我喜欢简洁的代码风格&quot;，下次对话它又从零开始。这就是 LLM 的&quot;金鱼记忆&quot;问题 -- 每次 API 调用都是无状态的，模型本身不会记住任何东西。</p><p><strong>记忆系统就是给 Agent 装上&quot;大脑的硬盘&quot;。</strong> 短期记忆让它在一次对话中保持连贯，长期记忆让它跨越多次对话记住用户偏好和历史经验。好的记忆系统是 Agent 从&quot;工具&quot;进化为&quot;助手&quot;的关键 -- 一个记得你的助手，和一个每次都要重新自我介绍的工具，体验天差地别。</p><p>这一章从最基础的对话历史管理讲起，经过摘要压缩、向量记忆检索等中级技巧，最后深入 MemGPT、时间衰减、记忆整合等前沿架构。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><ul><li><a href="./beginner.html">入门篇</a> -- 为什么需要记忆、消息历史管理、滑动窗口、持久化存储、Token 预算</li><li><a href="./intermediate.html">进阶篇</a> -- 短期 vs 长期记忆、摘要压缩、向量记忆检索、实体记忆、多层记忆系统</li><li><a href="./advanced.html">高级篇</a> -- MemGPT 架构、时间衰减、记忆整合与冲突、Generative Agents 记忆、记忆蒸馏</li></ul><h2 id="核心概念速览" tabindex="-1">核心概念速览 <a class="header-anchor" href="#核心概念速览" aria-label="Permalink to &quot;核心概念速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>一句话解释</th></tr></thead><tbody><tr><td>短期记忆</td><td>当前对话的消息历史，受上下文窗口限制</td></tr><tr><td>长期记忆</td><td>跨会话持久保存的信息（用户偏好、历史经验等）</td></tr><tr><td>滑动窗口</td><td>只保留最近 N 条消息的简单策略</td></tr><tr><td>摘要压缩</td><td>用 LLM 把长对话压缩成简短摘要，节省 Token</td></tr><tr><td>向量记忆</td><td>把记忆向量化存储，按语义相关性检索</td></tr><tr><td>实体记忆</td><td>提取和追踪对话中的关键实体（人名、偏好等）</td></tr><tr><td>MemGPT</td><td>受操作系统虚拟内存启发的记忆管理架构</td></tr><tr><td>时间衰减</td><td>越久远的记忆权重越低，模拟人类遗忘曲线</td></tr></tbody></table><h2 id="学完你能做到" tabindex="-1">学完你能做到 <a class="header-anchor" href="#学完你能做到" aria-label="Permalink to &quot;学完你能做到&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>能力</th></tr></thead><tbody><tr><td>入门</td><td>实现对话历史管理、设计滑动窗口策略、用 SQLite 持久化存储、管理 Token 预算</td></tr><tr><td>进阶</td><td>实现摘要压缩、构建向量记忆检索、提取实体信息、设计多层记忆系统</td></tr><tr><td>高级</td><td>理解 MemGPT 架构、实现时间衰减机制、处理记忆冲突、构建自主记忆管理 Agent</td></tr></tbody></table><h2 id="前置知识" tabindex="-1">前置知识 <a class="header-anchor" href="#前置知识" aria-label="Permalink to &quot;前置知识&quot;">​</a></h2><ul><li>已完成前面章节，特别是 RAG 章节中的 Embedding 和向量检索</li><li>理解 Python 文件 I/O 和 SQLite 基础</li><li>了解 Token 计数的概念</li></ul>',12)])])}const b=e(o,[["render",n]]);export{c as __pageData,b as default};
